SELECT boardNo, boardName, boardContent, fk_id, readCount, createdAtBoard
FROM board
WHERE fk_categoryNo = #{categoryNo, jdbcType=INTEGER}

SELECT boardNo, boardName, boardContent, fk_id, readCount, createdAtBoard
FROM board
WHERE boardNo = #{boardNo}

select commentNo, fk_id, fk_name, content, createdAtComment, updateAtComment, fk_boardNo, parentNo
from comments
where fk_boardNo = #{boardNo}
